namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string CourseCode { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", CourseCode = "CS101", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published research on CS education.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures & Algorithms", CourseCode = "CS201", Description = "Study fundamental data structures (trees, graphs, hash tables) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has contributed to open-source projects.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Operating Systems", CourseCode = "CS301", Description = "Explore process management, memory allocation, file systems, and concurrency in modern operating systems.", Credits = 4, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked at a major tech company for a decade before joining academia, specializing in distributed systems.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", CourseCode = "MATH101", Description = "Introduction to limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is an award-winning educator with a passion for making calculus accessible to all students.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", CourseCode = "MATH201", Description = "Study of vector spaces, linear transformations, matrices, and eigenvalues with applications in science and engineering.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma's research focuses on computational linear algebra and its applications in machine learning.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "Classical Mechanics", CourseCode = "PHYS101", Description = "Newtonian mechanics covering kinematics, dynamics, energy, momentum, and rotational motion.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim has authored multiple physics textbooks and is known for his engaging demonstrations.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 7, Title = "Electromagnetism", CourseCode = "PHYS201", Description = "Study of electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson conducts research in photonics and has published over 50 peer-reviewed papers.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 8, Title = "English Composition", CourseCode = "ENG101", Description = "Develop critical writing skills through essays, research papers, and peer review workshops.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Prof. Linda Hayes", InstructorBio = "Prof. Hayes is a published author and has mentored hundreds of students in academic writing.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 9, Title = "American Literature", CourseCode = "ENG202", Description = "Survey of American literary works from the colonial period to the present, exploring themes of identity and society.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres specializes in 20th-century American fiction and has received multiple teaching awards.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Title = "World History to 1500", CourseCode = "HIST101", Description = "Survey of world civilizations from ancient times through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Catherine Bell", InstructorBio = "Dr. Bell is an archaeologist who brings firsthand fieldwork experience to her teaching of ancient civilizations.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 11, Title = "Machine Learning", CourseCode = "CS401", Description = "Introduction to supervised and unsupervised learning, neural networks, and practical applications of ML in industry.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has contributed to open-source projects.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 12, Title = "Probability & Statistics", CourseCode = "MATH301", Description = "Introduction to probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma's research focuses on computational linear algebra and its applications in machine learning.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.CourseCode).ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app this would persist to a database
        return request.CourseId > 0
            && !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId);
    }
}

