@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Browse our departments and courses, and submit enrollment requests online.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in FeaturedCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode — @course.Title</h5>
                    <p class="card-text text-muted">@course.DepartmentName · @course.Credits credits</p>
                    <p class="card-text">@course.Description[..Math.Min(100, course.Description.Length)]...</p>
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-5">Departments</h2>
<div class="row">
    @foreach (var dept in Departments)
    {
        <div class="col-md-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-primary btn-sm">Browse @dept.Code Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> FeaturedCourses { get; set; } = new();
    private List<Department> Departments { get; set; } = new();

    protected override void OnInitialized()
    {
        FeaturedCourses = CatalogService.GetFeaturedCourses();
        Departments = CatalogService.GetDepartments();
    }
}

