@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@rendermode InteractiveServer
@inject CatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="SearchTerm" @bind:event="oninput" @onkeyup="Search" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId" @bind:after="Search">
            <option value="0">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (Courses.Any())
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in Courses)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No courses match your search criteria.</p>
}

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private string SearchTerm { get; set; } = string.Empty;
    private int SelectedDepartmentId { get; set; }
    private List<Course> Courses { get; set; } = new();
    private List<Department> Departments { get; set; } = new();

    protected override void OnInitialized()
    {
        Departments = CatalogService.GetDepartments();
        if (DepartmentId.HasValue)
            SelectedDepartmentId = DepartmentId.Value;
        Search();
    }

    private void Search()
    {
        Courses = CatalogService.GetCourses(SearchTerm, SelectedDepartmentId > 0 ? SelectedDepartmentId : null);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>@(Course?.Title ?? "Course Not Found")</PageTitle>

@if (Course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course could not be found.</p>
    <a href="courses" class="btn btn-primary">Back to Catalog</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active">@Course.CourseCode</li>
        </ol>
    </nav>

    <h1>@Course.CourseCode — @Course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@Course.Description</p>

            <h4 class="mt-4">Schedule</h4>
            <p><strong>@Course.Schedule</strong></p>

            <h4 class="mt-4">Credits</h4>
            <p><span class="badge bg-primary fs-6">@Course.Credits credits</span></p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@Course.InstructorName</h6>
                    <p class="card-text">@Course.InstructorBio</p>
                </div>
            </div>

            <div class="mt-3">
                <a href="enroll?courseId=@Course.Id" class="btn btn-success w-100">Request Enrollment</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? Course { get; set; }

    protected override void OnInitialized()
    {
        Course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService
@rendermode InteractiveServer

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Your enrollment request for <strong>@SelectedCourseName</strong> has been submitted successfully. You will receive a confirmation via your university email.</p>
        <a href="courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                    <ValidationMessage For="() => Model.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g., STU12345" />
                    <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseSelect" class="form-label">Course</label>
                    <InputSelect id="courseSelect" class="form-select" @bind-Value="Model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in Courses)
                        {
                            <option value="@course.Id">@course.CourseCode — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private EnrollmentRequest Model { get; set; } = new();
    private List<Course> Courses { get; set; } = new();
    private bool Submitted { get; set; }
    private string SelectedCourseName { get; set; } = string.Empty;

    protected override void OnInitialized()
    {
        Courses = CatalogService.GetCourses();
        if (CourseId.HasValue)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(Model.CourseId);
        SelectedCourseName = course is not null ? $"{course.CourseCode} — {course.Title}" : "Unknown";

        if (CatalogService.SubmitEnrollmentRequest(Model))
        {
            Submitted = true;
        }
    }
}

